{

	for(register int i=0;i<cnt;i++)

	{

		boss[i]=i;

	}

}

inline void update()

{

	for(register int i=0;i<nc;i++)

	{

		dist[i]=min(dist[i],dist[(i+nc-1)%nc]+2);

	}

}

